easy.solution:
// TypeScript implementation for Pick and Omit
interface PickandOmitPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processPickandOmit(item: PickandOmitPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processPickandOmit({ id: 1, title: 'Pick and Omit', status: 'active' }));

